const raw = $input.first().json;
let input = raw.body || raw;

if (typeof input === 'string') {
  try { input = JSON.parse(input); } catch(e) {}
}

if (input.body && typeof input.body === 'object') {
  input = input.body;
}

if (!input.service_name && raw.body?.service_name) {
  input = { ...input, ...raw.body };
}

return { json: input };

const d = $input.first().json;
const scorePercent = Math.round(d.consensus_score * 100);
const emoji = d.consensus_score >= 0.5 ? '🔴' : '🟡';

const agentLine = (name, agent) => `${name}: score=${agent?.score ?? 'N/A'} | action=${agent?.recommended_action ?? 'N/A'} | reason: ${agent?.reasoning ?? 'N/A'}`;

const body = [
  `${emoji} AutoFlow Alert — Action May Be Needed`,
  ``,
  `Service: ${d.service_name} in namespace: ${d.namespace}`,
  `Metric: ${d.metric_type} = ${d.metric_value}`,
  `Consensus Score: ${scorePercent}% (threshold for auto-fix is 60%)`,
  `Decision: ALERT — monitoring, no auto-remediation yet`,
  ``,
  `Agent Analysis:`,
  agentLine('Anomaly Agent', d.agents?.anomaly),
  agentLine('Risk Agent   ', d.agents?.risk),
  agentLine('SLA Agent    ', d.agents?.sla),
  agentLine('Context Agent', d.agents?.context),
  ``,
  `Decision ID: ${d.decision_id}`,
  `Time: ${new Date().toISOString()}`
].join('\n');

return { json: { ...d, email_body: body } };

const raw = $input.first().json;
let input = raw.body || raw;

// Handle case where body is a JSON string (double-serialized)
if (typeof input === 'string') {
  try { input = JSON.parse(input); } catch(e) { /* keep as-is */ }
}

// Handle case where body is nested one more level
if (input.body && typeof input.body === 'object') {
  input = input.body;
}

// Safety: if trigger exists but service_name doesn't, 
// try extracting from the raw webhook payload
if (!input.service_name && raw.body?.service_name) {
  input = { ...input, ...raw.body };
}

return { json: input };

const input = $json;
const action = input.remediation_action || 'restart_pod';
const validActions = ['restart_pod', 'scale_service', 'reroute_traffic', 'cleanup_disk', 'reschedule_pod', 'drain_node'];
const resolvedAction = validActions.includes(action) ? action : 'restart_pod';
return { json: { ...input, resolved_action: resolvedAction } };

const d = $('Remediate — Receive Decision').first().json;
return {
  json: {
    ...d,
    action_simulated: true,
    simulation_note: `SIMULATED restart_pod: would DELETE pod for ${d.service_name} in ${d.namespace}. K8s would auto-recreate it.`,
    k8s_command: `kubectl delete pod -l app=${d.service_name} -n ${d.namespace} --grace-period=0`
  }
};

const d = $('Remediate — Receive Decision').first().json;
const currentReplicas = 2;
const newReplicas = Math.min(currentReplicas * 2, 10);
return {
  json: {
    ...d,
    action_simulated: true,
    current_replicas: currentReplicas,
    new_replicas: newReplicas,
    simulation_note: `SIMULATED scale_service: would PATCH deployment ${d.service_name} from ${currentReplicas} to ${newReplicas} replicas.`,
    k8s_command: `kubectl scale deployment ${d.service_name} --replicas=${newReplicas} -n ${d.namespace}`
  }
};

const d = $('Remediate — Receive Decision').first().json;
return {
  json: {
    ...d,
    action_simulated: true,
    simulation_note: `SIMULATED reroute_traffic: would update Ingress to redirect traffic away from ${d.service_name} in ${d.namespace}. Manual ingress update required in production.`,
    k8s_command: `kubectl annotate ingress ${d.service_name}-ingress nginx.ingress.kubernetes.io/service-upstream=true -n ${d.namespace}`
  }
};

const data = $input.first().json;
const base = $('Remediate — Receive Decision').first().json;
const action_id = `act_${Date.now()}_${Math.random().toString(36).substr(2,9)}`;

// Merge: prefer base (which has decision data), overlay with action data
const merged = {
  ...base,
  action_id,
  action_taken: base.resolved_action || base.remediation_action || data.resolved_action || 'restart_pod',
  action_simulated: data.action_simulated || true,
  simulation_note: data.simulation_note || '',
  k8s_command: data.k8s_command || '',
  new_replicas: data.new_replicas || null,
  action_executed_at: new Date().toISOString(),
  detection_timestamp: base.timestamp
};

// Safety check — log what we have
if (!merged.decision_id) {
  // Try to recover from data (simulate node output has ...d spread)
  merged.decision_id = data.decision_id || 'unknown';
  merged.event_id = data.event_id || merged.event_id || 'unknown';
  merged.service_name = data.service_name || merged.service_name || 'unknown';
  merged.namespace = data.namespace || merged.namespace || 'default';
}

return { json: merged };

const original = $('Remediate — Receive Decision').first().json;
const actionData = $('Merge Action Paths').first().json;

const thresholds = {
  cpu_usage: 85,
  memory_usage: 90,
  error_rate: 5,
  latency_ms: 2000,
  disk_usage: 95,
  disk_space_free_percent: 10,
  pod_scheduling: 0.5
};
const threshold = thresholds[original.metric_type] || 80;

let simulatedCurrentValue;
let recovered;

if (original.metric_type === 'pod_scheduling') {
  const rescheduleSuccess = Math.random() > 0.15;
  simulatedCurrentValue = rescheduleSuccess ? 0 : 1;
  recovered = simulatedCurrentValue === 0;
} else if (original.metric_type === 'disk_space_free_percent') {
  const cleanupSuccess = Math.random() > 0.1;
  simulatedCurrentValue = cleanupSuccess ?
    threshold + (Math.random() * 20 + 5) :
    original.metric_value * (0.9 + Math.random() * 0.15);
  recovered = simulatedCurrentValue >= threshold;
} else {
  // FIXED: Realistic recovery simulation
  // ~70% chance of recovery, not ~100%
  const recoveryChance = Math.random();
  if (recoveryChance < 0.70) {
    // Recovered: value drops well below threshold
    simulatedCurrentValue = threshold * (0.4 + Math.random() * 0.3);
  } else {
    // NOT recovered: value stays above or near threshold
    simulatedCurrentValue = threshold * (0.85 + Math.random() * 0.3);
  }
  recovered = simulatedCurrentValue < (threshold * 0.8);
}

const detectedAt = new Date(original.timestamp || actionData.action_executed_at).getTime();
const resolvedAt = Date.now();
const mttrSeconds = Math.round((resolvedAt - detectedAt) / 1000);

return {
  json: {
    ...original,
    action_id: actionData.action_id,
    action_taken: actionData.action_taken,
    recovery_metric_value: Math.round(simulatedCurrentValue * 100) / 100,
    recovery_threshold: original.metric_type === 'pod_scheduling' ? 0 : (original.metric_type === 'disk_space_free_percent' ? threshold : threshold * 0.8),
    recovered,
    mttr_seconds: mttrSeconds,
    agents: original.agents
  }
};

const raw = $input.first().json;
let input = raw.body || raw;

if (typeof input === 'string') {
  try { input = JSON.parse(input); } catch(e) {}
}

if (input.body && typeof input.body === 'object') {
  input = input.body;
}

const outcome = input.recovered === true ? 'success' : 'failure';
return { json: { ...input, outcome } };

const outcome = $('Learning — Receive Outcome').first().json;
const isSuccess = outcome.outcome === 'success';
const agents = outcome.agents || {};

const LEARNING_RATE = 0.05;
const MIN_WEIGHT = 0.05;
const MAX_WEIGHT = 0.60;

const current = {};
$('Fetch Current Weights').all().forEach(row => {
  current[row.json.agent_name] = {
    weight: parseFloat(row.json.current_weight),
    initial: parseFloat(row.json.initial_weight),
    total: parseInt(row.json.total_predictions) || 0,
    correct: parseInt(row.json.correct_predictions) || 0
  };
});

const defaults = { anomaly: 0.30, risk: 0.35, sla: 0.25, context: 0.10 };
const updated = {};
const agentNames = ['anomaly', 'risk', 'sla', 'context'];

agentNames.forEach(name => {
  const agentData = agents[name] || {};
  const c = current[name] || { weight: defaults[name], initial: defaults[name], total: 0, correct: 0 };

  // High-scoring agents flagged a real problem — reward them on both success and failure
  // (failure = wrong action chosen, not wrong detection)
  const agentWasCorrect = (agentData.score || 0) > 0.5;

  let newWeight = c.weight;
  if (agentWasCorrect) {
    newWeight = Math.min(c.weight * (1 + LEARNING_RATE), MAX_WEIGHT);
  } else {
    newWeight = Math.max(c.weight * (1 - LEARNING_RATE), MIN_WEIGHT);
  }

  updated[name] = {
    agent_name: name,
    old_weight: c.weight,
    new_weight: Math.round(newWeight * 10000) / 10000,
    was_correct: agentWasCorrect,
    total_predictions: c.total + 1,
    correct_predictions: c.correct + (agentWasCorrect ? 1 : 0)
  };
});

// Normalise so weights sum to exactly 1.0
const total = Object.values(updated).reduce((sum, w) => sum + w.new_weight, 0);
Object.keys(updated).forEach(k => {
  updated[k].new_weight = Math.round((updated[k].new_weight / total) * 10000) / 10000;
});

// Fix floating point drift — always adjust risk agent
const sumCheck = Object.values(updated).reduce((s, w) => s + w.new_weight, 0);
const diff = Math.round((1.0 - sumCheck) * 10000) / 10000;
if (Math.abs(diff) > 0) {
  updated['risk'].new_weight = Math.round((updated['risk'].new_weight + diff) * 10000) / 10000;
}

return {
  json: {
    event_id: outcome.event_id,
    decision_id: outcome.decision_id,
    outcome: outcome.outcome,
    updated_weights: updated,
    learning_applied_at: new Date().toISOString()
  }
};

