UPDATE autoflow_agent_weights SET current_weight = {{ $json.updated_weights.anomaly.new_weight }}, total_predictions = {{ $json.updated_weights.anomaly.total_predictions }}, correct_predictions = {{ $json.updated_weights.anomaly.correct_predictions }}, updated_at = NOW() WHERE agent_name = 'anomaly';

