const d = $('Remediate — Receive Decision').first().json;
const mountpoint = d.mountpoint || '/';
const nodeName = d.node_name || d.service_name;
return {
  json: {
    ...d,
    action_simulated: true,
    simulation_note: `SIMULATED cleanup_disk: would run cleanup on node ${nodeName} mountpoint ${mountpoint}. Actions: prune unused container images, clear old logs, remove temp files.`,
    k8s_command: `kubectl exec -n monitoring deploy/our-node-exporter -- sh -c "docker system prune -f && journalctl --vacuum-size=100M" # on node ${nodeName}`
  }
};

const d = $('Remediate — Receive Decision').first().json;
const podName = d.pod_name || `${d.service_name}-pod`;
const ns = d.namespace || 'default';
return {
  json: {
    ...d,
    action_simulated: true,
    simulation_note: `SIMULATED reschedule_pod: would DELETE unschedulable pod ${podName} in ${ns} and let the scheduler retry placement. If persistent, would relax nodeSelector/affinity constraints.`,
    k8s_command: `kubectl delete pod ${podName} -n ${ns} --grace-period=0 && kubectl get events -n ${ns} --field-selector reason=FailedScheduling`
  }
};

const d = $('Remediate — Receive Decision').first().json;
const nodeName = d.node_name || 'minikube';
return {
  json: {
    ...d,
    action_simulated: true,
    simulation_note: `SIMULATED drain_node: would CORDON and DRAIN node ${nodeName}, evicting all pods to healthy nodes. Node marked unschedulable until disk/resource issue resolved.`,
    k8s_command: `kubectl cordon ${nodeName} && kubectl drain ${nodeName} --ignore-daemonsets --delete-emptydir-data --grace-period=30`
  }
};
